@fleer.paranoia += 4


// ── The plan: delivery-of-import ─────────────────────────────────────────────
//
// Queued by mail-package. Coordinates a rumor in the tavern, a third-party
// interception of the parcel, and a final confrontation between sender and
// target. The confrontation precasts the original mail-package action in the
// @triggering role, producing a non-reaction-mediated causal edge (runtime
// mechanism #1) — visible in the sifting-match diagram as a convergence that
// doesn't pass through the normal reaction chain.

queue plan delivery-of-import:
            with:
                @sender: @sender
                @target: @target
                @parcel: @parcel
                @triggering: @this


// ── Sign-reading lineage ─────────────────────────────────────────────────────

queue action overhear:
            with:
                @listener: @confidant
                @source: @speaker
            time:
                between: 0 minutes and 3 minutes from action

queue action mutter-aside:
            with:
                @speaker: @listener
                @confidant: @source
            time:
                between: 1 minutes and 3 minutes from action

queue action confront:
            with:
                @accuser: @listener
                @accused: @source
            abandon:
                @listener.paranoia < 55
            time:
                between: 0 minutes and 5 minutes from action

queue action inspect-postcard:
            with:
                @reader: @receiver
                @card: @card
            time:
                between: 5 minutes and 20 minutes from action

queue action read-wall:
            with:
                @reader: @scrawler
                @wall: @wall
            time:
                between: 0 minutes and 12 minutes from action
